// ─── Tanklevel Sensor Function
// Receives a tank level percentage (0-100) from your sensor
// Sets flow.tankLevel to 0 (fault) or null (clear)
// Sends msg.topic = 'tanklevel' downstream to the sequencer

const level     = msg.payload;
const threshold = flow.get("tankThreshold"); // set this via a change/inject node

// Validate incoming level is a number
if (typeof level !== "number") {
    node.warn("Level is not a number: " + level);
    return null;
}

// Ensure threshold has been configured
if (threshold === null || threshold === undefined) {
    node.warn("Threshold not set yet in flow context");
    return null;
}

// Validate level is within expected range
if (level < 0 || level > 100) {
    node.warn("Level out of range: " + level);
    return null;
}

// Emergency shutoff — tank critically full regardless of threshold
if (level > 95) {
    flow.set("tankLevel", 0);
    node.status({ fill: "red", shape: "dot", text: `OFF — emergency shutoff at ${level}%` });
    msg.topic   = "tanklevel";
    msg.payload = 0;
    return msg;
}

// Above threshold — fault condition, stop the system
if (level >= threshold) {
    flow.set("tankLevel", 0);
    node.status({ fill: "red", shape: "dot", text: `OFF — ${level}% >= ${threshold}%` });
    msg.topic   = "tanklevel";
    msg.payload = 0;
    return msg;
}

// Below threshold — system clear, ON requests allowed
flow.set("tankLevel", null);
node.status({ fill: "green", shape: "dot", text: `OK — ${level}% < ${threshold}%` });
msg.topic   = "tanklevel";
msg.payload = null;
return msg;

const updates = msg.payload.updates;
if (!updates) return null;

// Signal K paths for wind
const windPaths = {
    "environment.wind.speedApparent": "windSpeed",
    "environment.wind.angleApparent": "windAngle"
    // If you want true wind instead, use:
    // "environment.wind.speedTrue": "windSpeedTrue",
    // "environment.wind.angleTrue": "windAngleTrue"
};

const messages = [];

for (const update of updates) {
    for (const v of update.values) {
        if (windPaths[v.path] !== undefined) {
            messages.push({
                topic: windPaths[v.path],
                payload: v.value,
                timestamp: update.timestamp
            });
        }
    }
}

return messages.length > 0 ? [messages] : null;

// Battery State of Charge Hysteresis Controller
// Output: 1 when SOC exceeds 96%, 0 when SOC drops below 92%
// Switch Mode 2 (AUTO) = SOC/override logic, ignores switch ON/OFF outputs
// Switch Mode 1 (ON) = force 1, Switch Mode 0 (OFF) = force 0
// Over 4800W ON = force 0 (overrides Shore Power ON), Over 4800W OFF = clear overrides
// Shore Power ON = force 1, Shore Power OFF = clear overrides
// STBD Engine ON = force 0, STBD Engine OFF = clear overrides

const HIGH_THRESHOLD = 96;
const LOW_THRESHOLD = 92;

// Retrieve state from context
let currentState = context.get('state') || 0;

// Update context with latest input values if present in message
if (msg.topic === 'switch')      context.set('switch', msg.payload);
if (msg.topic === 'switchMode')  context.set('switchMode', msg.payload);
if (msg.topic === 'shorePower')  context.set('shorePower', msg.payload);
if (msg.topic === 'over4800')    context.set('over4800', msg.payload);
if (msg.topic === 'stbdEngine')  context.set('stbdEngine', msg.payload);
if (msg.topic === 'soc')         context.set('soc', msg.payload);

// Read latest known values from context
let switchState = context.get('switch');
let switchMode  = context.get('switchMode');
let shorePower  = context.get('shorePower');
let over4800    = context.get('over4800');
let stbdEngine  = context.get('stbdEngine');
let soc         = context.get('soc');

// --- Switch Logic (highest priority) ---

// If switch is in AUTO mode, ignore switch ON/OFF outputs and fall through
if (switchMode === 2) {
    node.status({ fill: 'blue', shape: 'dot', text: 'Switch: AUTO - SOC active' });
    // Fall through to override and SOC logic - do NOT process switch state
}

// Only process switch ON/OFF if NOT in AUTO mode
else if (switchMode !== 2) {

    // Switch ON forces output ON
    if (switchState === 1) {
        currentState = 1;
        context.set('state', currentState);
        node.status({ fill: 'green', shape: 'dot', text: 'Switch: Forced ON' });
        msg.payload = currentState;
        return msg;
    }

    // Switch OFF forces output OFF
    if (switchState === 0) {
        currentState = 0;
        context.set('state', currentState);
        node.status({ fill: 'red', shape: 'dot', text: 'Switch: Forced OFF' });
        msg.payload = currentState;
        return msg;
    }
}

// --- Override Logic (priority order) ---

// Over 4800W ON forces output OFF - overrides Shore Power ON
if (over4800 === true || over4800 === 1) {
    currentState = 0;
    context.set('state', currentState);
    node.status({ fill: 'orange', shape: 'dot', text: 'Over 4800W: Forced OFF' });
    msg.payload = currentState;
    return msg;
}

// STBD Engine ON forces output OFF
if (stbdEngine === true || stbdEngine === 1) {
    currentState = 0;
    context.set('state', currentState);
    node.status({ fill: 'orange', shape: 'dot', text: 'STBD Engine: Forced OFF' });
    msg.payload = currentState;
    return msg;
}

// Shore Power ON forces output ON
if (shorePower === true || shorePower === 1) {
    currentState = 1;
    context.set('state', currentState);
    node.status({ fill: 'blue', shape: 'dot', text: 'Shore Power: Forced ON' });
    msg.payload = currentState;
    return msg;
}

// Shore Power OFF, Over 4800W OFF, or STBD Engine OFF clears overrides
if (shorePower === false || shorePower === 0) {
    context.set('shorePower', null);
}
if (over4800 === false || over4800 === 0) {
    context.set('over4800', null);
}
if (stbdEngine === false || stbdEngine === 0) {
    context.set('stbdEngine', null);
}

// --- SOC Hysteresis Logic ---
if (typeof soc !== 'number' || soc < 0 || soc > 100) {
    node.warn('Invalid or missing SOC value: ' + soc);
    return null;
}

if (soc > HIGH_THRESHOLD) {
    currentState = 1;
} else if (soc < LOW_THRESHOLD) {
    currentState = 0;
}

context.set('state', currentState);
node.status({ fill: currentState ? 'green' : 'red', shape: 'dot', text: 'SOC: ' + soc + '% -> State: ' + currentState });

msg.payload = currentState;
return msg;

if (msg.payload === 1) {
    msg.payload = { "/SwitchableOutput/output_1/State": 1 };
} else if (msg.payload === 0) {
    msg.payload = { "/SwitchableOutput/output_1/State": 0 };
}
return msg;

// ╔══════════════════════════════════════════════════════════════════╗
// ║                      WATERMAKER FLUSH TIMER                      ║
// ╠══════════════════════════════════════════════════════════════════╣
// ║  INPUTS (all wired to the single input, routed by msg.topic)    ║
// ║    msg.topic = "reset"   → restart cycle from OFF phase         ║
// ║                            (only if timer is currently running) ║
// ║    msg.topic = "enable"  → msg.payload true=start, false=stop   ║
// ║    msg.topic = "bypass"  → fire ON once instantly for ON_DELAY  ║
// ║                            ms then OFF, behaviour depends on    ║
// ║                            timer state (see bypass section)     ║
// ╠══════════════════════════════════════════════════════════════════╣
// ║  OUTPUTS                                                        ║
// ║    Output 1 → payload: 1  (ON signal)                           ║
// ║    Output 2 → payload: 0  (OFF signal)                          ║
// ║    Output 3 → status string for debug                           ║
// ╚══════════════════════════════════════════════════════════════════╝

// ─── Adjustable timing constants ───────────────────────────────────
// Enter your desired flush (ON_DELAY) & interval (OFF_DELAY) times here
// ON_DELAY  → enter a value in MINUTES  (e.g. 11 mins)
// OFF_DELAY → enter a value in HOURS    (e.g. 72 = 3 days)

const ON_DELAY_MINUTES  = 11;      // ← change this value (minutes)
const OFF_DELAY_HOURS   = 72;      // ← change this value (hours)

// Unit conversions — do not change these
const ON_DELAY  = ON_DELAY_MINUTES * 60 * 1000;          // minutes → ms
const OFF_DELAY = OFF_DELAY_HOURS  * 60 * 60 * 1000;     // hours   → ms
// ───────────────────────────────────────────────────────────────────


// ─── clearTimers() ─────────────────────────────────────────────────
// Cancels any pending ON or OFF timeouts that are currently waiting.
// Always call this before starting a new cycle to avoid two cycles
// running at the same time.
function clearTimers() {
    const t1 = context.get("onTimer");
    const t2 = context.get("offTimer");
    if (t1) clearTimeout(t1);
    if (t2) clearTimeout(t2);
    context.set("onTimer",  null);
    context.set("offTimer", null);
}


// ─── startCycle() ──────────────────────────────────────────────────
// Clears any existing timers, marks the timer as enabled, then
// kicks off the repeating OFF → ON → OFF → ON loop.
// The cycle always begins with the OFF phase.
function startCycle() {
    clearTimers();
    context.set("enabled", true);

    // doOff() — sends payload 0 on Output 2, then schedules doOn()
    function doOff() {
        // If the timer was disabled while we were waiting, abort
        if (!context.get("enabled")) return;

        // Send OFF signal on Output 2, leave Output 1 silent, log to Output 3
        node.send([
            null,                              // Output 1 — silent
            { payload: 0, topic: "timer" },   // Output 2 — OFF
            { payload: "OFF" }                 // Output 3 — debug status
        ]);

        // Schedule the ON phase after OFF_DELAY milliseconds
        const t = setTimeout(doOn, OFF_DELAY);
        context.set("offTimer", t);
    }

    // doOn() — sends payload 1 on Output 1, then schedules doOff()
    function doOn() {
        // If the timer was disabled while we were waiting, abort
        if (!context.get("enabled")) return;

        // Send ON signal on Output 1, leave Output 2 silent, log to Output 3
        node.send([
            { payload: 1, topic: "timer" },   // Output 1 — ON
            null,                              // Output 2 — silent
            { payload: "ON" }                  // Output 3 — debug status
        ]);

        // Schedule the OFF phase after ON_DELAY milliseconds
        const t = setTimeout(doOff, ON_DELAY);
        context.set("onTimer", t);
    }

    // Start the cycle immediately with the OFF phase
    doOff();
}


// ─── fireOnOnce(thenRestartCycle) ──────────────────────────────────
// Fires ON instantly for ON_DELAY ms then sends OFF.
// The thenRestartCycle argument controls what happens after the pulse:
//
//   thenRestartCycle = true  → restart the full OFF→ON loop after OFF
//                              is sent. Used when bypass is triggered
//                              while the timer is RUNNING.
//
//   thenRestartCycle = false → stop after the OFF pulse. Timer stays
//                              disabled. Used when bypass is triggered
//                              while the timer is STOPPED.
function fireOnOnce(thenRestartCycle) {
    clearTimers();

    // Do NOT set enabled to true here — if thenRestartCycle is false
    // the timer must stay disabled after the pulse. If thenRestartCycle
    // is true, startCycle() will set enabled to true after the pulse.

    // Send ON instantly
    node.send([
        { payload: 1, topic: "timer" },       // Output 1 — ON
        null,                                  // Output 2 — silent
        { payload: "ON (bypass)" }             // Output 3 — debug status
    ]);

    // After ON_DELAY, send OFF then decide whether to restart the cycle
    const t = setTimeout(() => {

        // Send OFF
        node.send([
            null,
            { payload: 0, topic: "timer" },   // Output 2 — OFF
            { payload: thenRestartCycle        // Output 3 — debug status
                ? "OFF (bypass) — restarting cycle"
                : "OFF (bypass) — stopped" }
        ]);

        // If called from a running timer, restart the cycle from OFF phase
        if (thenRestartCycle) {
            startCycle();
        }

    }, ON_DELAY);

    context.set("onTimer", t);
}


// ═══════════════════════════════════════════════════════════════════
//  INPUT ROUTING — decides what to do based on msg.topic
// ═══════════════════════════════════════════════════════════════════

if (msg.topic === "reset") {
    // ── RESET ──────────────────────────────────────────────────────
    // Only restarts the cycle if the timer is currently running.
    // If the timer is stopped, the reset is ignored entirely.
    const isEnabled = context.get("enabled") || false;

    if (isEnabled) {
        // Timer is running — restart the cycle from the OFF phase
        startCycle();
    } else {
        // Timer is stopped — ignore the reset and log to debug
        node.send([
            null,
            null,
            { payload: "RESET ignored — timer is stopped" }  // Output 3 — debug status
        ]);
    }

} else if (msg.topic === "enable") {
    // ── ENABLE / DISABLE ───────────────────────────────────────────
    // msg.payload = true  → start (or restart) the cycle from OFF phase
    // msg.payload = false → stop the cycle and send a final OFF signal
    if (msg.payload === true || msg.payload === 1) {
        startCycle();
    } else {
        // Stop the cycle by clearing timers and flagging as disabled
        clearTimers();
        context.set("enabled", false);

        // Send a final OFF to make sure the output doesn't stay ON
        node.send([
            null,
            { payload: 0, topic: "timer" },   // Output 2 — OFF
            { payload: "DISABLED" }            // Output 3 — debug status
        ]);
    }

} else if (msg.topic === "bypass") {
    // ── BYPASS ─────────────────────────────────────────────────────
    // Behaviour depends on whether the timer is currently running:
    //
    //   Timer is RUNNING (enabled = true):
    //     → Fire ON instantly for ON_DELAY ms, send OFF, then restart
    //       the cycle from the OFF phase. The cycle continues looping.
    //
    //   Timer is STOPPED (enabled = false):
    //     → Fire ON instantly for ON_DELAY ms, send OFF, then stop.
    //       The timer stays disabled — it will NOT begin looping.

    const isEnabled = context.get("enabled") || false;

    if (isEnabled) {
        // Timer is running — pulse ON then restart the cycle
        node.send([
            null,
            null,
            { payload: "BYPASS — pulsing ON then restarting cycle" }
        ]);
        fireOnOnce(true);    // true = restart cycle after the pulse
    } else {
        // Timer is stopped — pulse ON once then stay stopped
        fireOnOnce(false);   // false = stop after the pulse
    }
}

// All output is handled via node.send() inside the functions above.
// Returning null here tells Node-RED not to send any additional message.
return null;

// ─── WATERMAKER PUMP LOGIC OPERATION
// Input:  msg.payload 1/0 = ON/OFF request
//         msg.topic 'tanklevel' with payload 0/null = fault/clear
// Output 1: Relay 1 — BOOST pump (5 sec delayed on OFF sequence)
// Output 2: Relay 2 — HIGH PRESSURE pump (15s delayed on ON sequence)
// Output 3: Relay 3 — FLUSH REQUEST (normally OFF) — used in OFF sequence
// Output 4: Relay 4 — ENSURE FLUSH VALVE IS CLOSED — used in ON sequence
//
// ON sequence:  Out4 → 0 immediately, Out1 → 1 immediately, Out2 → 1 after 15s
// OFF sequence: Out2 → 0 immediately, Out1 → 0 after 5s, Out3 → 1 after 15s
//
// ON is blocked if flow.tankLevel is 0
// Tanklevel fault while running triggers OFF sequence automatically

// ─── Read current state from flow context
let running   = flow.get('running')   || false;
let tankLevel = flow.get('tankLevel'); // null = clear, 0 = fault/blocked

// ─── Helper — sends a message on one or more of the 4 output wires
// Pass null on any output you don't want to fire
function send(out1, out2, out3, out4) {
    node.send([
        out1 !== null ? { payload: out1 } : null,
        out2 !== null ? { payload: out2 } : null,
        out3 !== null ? { payload: out3 } : null,
        out4 !== null ? { payload: out4 } : null
    ]);
}

// ─── OFF sequence
// Immediately stops Out2, then Out1 after 5s, then restores Out3 after 15s
function runOff() {
    flow.set('running', false);
    send(null, 0, null, null);                          // Out2 → OFF immediately
    setTimeout(() => send(0, null, null, null), 5000);  // Out1 → OFF after 5s
    setTimeout(() => send(null, null, 1, null), 15000); // Out3 → ON after 15s (5+10)
}

// ─── ON sequence
// Immediately fires Out4 and starts Out1, then starts Out2 after 15s
function runOn() {
    flow.set('running', true);
    send(null, null, null, 0);                           // Out4 → OFF immediately
    send(1, null, null, null);                           // Out1 → ON immediately
    setTimeout(() => send(null, 1, null, null), 15000);  // Out2 → ON after 15s
}

// ─── Tanklevel topic handler
// Receives messages from the tanklevel sensor function node
// payload 0    = fault — block ON requests, trigger OFF if currently running
// payload null = clear — unblock ON requests
if (msg.topic === 'tanklevel') {
    const val = msg.payload;

    if (val === 0 || val === '0') {
        flow.set('tankLevel', 0);
        if (flow.get('running')) {
            // System is running — execute OFF sequence immediately
            runOff();
        }
        // If not running — just hold blocked state, no OFF sequence needed

    } else if (val === null) {
        // Tank level back below threshold — clear the block
        flow.set('tankLevel', null);

    } else {
        // Any other value treated as clear (e.g. 1, "ok")
        flow.set('tankLevel', null);
    }

    return null;
}

// ─── ON request
// Blocked if tankLevel is 0 — must wait for null to clear
if (msg.payload === 1 || msg.payload === '1') {
    if (flow.get('tankLevel') === 0) {
        node.warn('ON blocked — tankLevel fault active, waiting for clear');
        return null;
    }
    runOn();
    return null;
}

// ─── OFF request
// Ignored if system is not currently running
if (msg.payload === 0 || msg.payload === '0') {
    if (!flow.get('running')) {
        return null; // already off, nothing to do
    }
    runOff();
    return null;
}

return null;
